-- Step 09: load [social_media_posts] part 2/9
SET XACT_ABORT ON;
BEGIN TRAN;
IF OBJECT_ID(N'dbo.social_media_posts', N'U') IS NOT NULL
BEGIN
  IF EXISTS (SELECT 1 FROM sys.identity_columns WHERE object_id = OBJECT_ID(N'dbo.social_media_posts')) SET IDENTITY_INSERT dbo.social_media_posts ON;
  IF EXISTS (SELECT 1 FROM sys.identity_columns WHERE object_id = OBJECT_ID(N'dbo.social_media_posts')) SET IDENTITY_INSERT dbo.social_media_posts OFF;
END
COMMIT;
